                evs=mbm[mc]; comps=[e['comp_abs'] for e in evs]
                k=bisect.bisect_right(comps, run[0]['start_abs'])-1
                intro=evs[k] if k>=0 else None
                rejf=[b for b in run if b['result']=='REJECTED']
                episodes.append((mc,p,intro,rejf,run))
            i=j+1
        else: i+=1

print(f"\nTotal real fault episodes: {len(episodes)}")
print(f"{'prod':6s}{'mach':6s}{'INTRO_wo':11s}{'tech':9s}{'reason':22s}{'nrej':>4s}  z-of-rejected")
