bymp=collections.defaultdict(list)
for b in batches: bymp[(b['machine_id'],b['product_id'])].append(b)

def run(FA_thresh, ELEV, ceil_gap):
    FA=set(p for p in byprod if max(x['z'] for x in batches if x['product_id']==p)>FA_thresh)
    ceil={}
    for p in FA:
        upper=sorted(z for z in (b['z'] for b in batches if b['product_id']==p) if z>=4.0)
        c=None
        for i in range(1,len(upper)):
            if upper[i]-upper[i-1]>=ceil_gap: c=(upper[i-1]+upper[i])/2; break
        ceil[p]=c if c else 6.0
    def clearfault(b): return b['result']=='REJECTED' and b['product_id'] in FA and b['z']>ceil[b['product_id']]
    eps=[]
    for (mc,p),bs in bymp.items():
        if p not in FA: continue
        bs.sort(key=lambda x:x['start_abs']); i=0
        while i<len(bs):
            if bs[i]['z']>ELEV:
                j=i
                while j+1<len(bs) and bs[j+1]['z']>ELEV: j+=1
                run_=bs[i:j+1]
                if any(clearfault(b) for b in run_):
                    evs=mbm[mc]; comps=[e['comp_abs'] for e in evs]
                    k=bisect.bisect_right(comps,run_[0]['start_abs'])-1
                    intro=evs[k] if k>=0 else None
                    eps.append((p,intro,[b for b in run_ if b['result']=='REJECTED']))
                i=j+1
            else: i+=1
    tb=collections.defaultdict(list)
    for p,intro,rejf in eps:
        if intro:
            for b in rejf: tb[intro['tech']].append((intro['wo'],p))
    conf={t for t,it in tb.items() if len(it)>=3 and len(set(w for w,_ in it))>=2}
    pt=collections.defaultdict(set)
    for t in conf:
        for w,p in tb[t]: pt[p].add(t)
    return {p:sorted(pt[p]) for p in sorted(pt)}, sorted(conf)

base=None
for FA_t in [6.5,7.0,7.5]:
  for ELEV in [3.0,3.5,4.0]:
    for cg in [1.2,1.5]:
      ans,conf=run(FA_t,ELEV,cg)
      key=json.dumps(ans,sort_keys=True)
      tag=f"FA>{FA_t} ELEV>{ELEV} gap>={cg}"
      if base is None: base=key; print(f"BASE [{tag}]: techs={conf}\n  {json.dumps(ans)}")
      print(f"  {tag}: {'SAME' if key==base else 'DIFFERENT'}  techs={conf}")
      if key!=base: print(f"     -> {json.dumps(ans)}")
